%[text] # 例4.6（sinc配列のDSFT）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example04_06"; % mfilename
%%
omegac = 0.5*pi;

Delta = pi/omegac;
h = @(n) sinc(n/Delta)/Delta;

freqz(h(-2000:2000),1,4096,'whole') %[output:7c19e79d]
